# Flat list of every flight code (needed to fit the encoder the same
# way it was fit during training, on the full column at once).
ALL_FLIGHTS = sorted({code for codes in AIRLINE_FLIGHTS.values() for code in codes})

# Build the encoders once (order fed in doesn't matter, LabelEncoder sorts internally)
airline_le = LabelEncoder().fit(AIRLINES)
city_le = LabelEncoder().fit(CITIES)
time_le = LabelEncoder().fit(TIME_SLOTS)
stops_le = LabelEncoder().fit(STOPS)
class_le = LabelEncoder().fit(CLASSES)
duration_cat_le = LabelEncoder().fit(DURATION_CATEGORIES)
flight_le = LabelEncoder().fit(ALL_FLIGHTS)

# All valid source-destination routes (excluding same city to same city)
ROUTES = sorted(f"{s}-{d}" for s in CITIES for d in CITIES if s != d)
route_le = LabelEncoder().fit(ROUTES)


def get_duration_category(duration):
    """Reproduces the pd.cut bins used during training."""
    if duration <= 2:
        return "Short"
    elif duration <= 5:
        return "Medium"
    elif duration <= 10:
        return "Long"
    else:
        return "Very Long"


# Input fields
airline = st.selectbox("Airline", AIRLINES)

# Flight code depends on the chosen airline, so build its options dynamically
flight = st.selectbox("Flight Code", AIRLINE_FLIGHTS[airline])

source_city = st.selectbox("Source City", CITIES)
departure_time = st.selectbox("Departure Time", TIME_SLOTS)
stops = st.selectbox("Number of Stops", STOPS)
arrival_time = st.selectbox("Arrival Time", TIME_SLOTS)
destination_city = st.selectbox("Destination City", [c for c in CITIES if c != source_city])
travel_class = st.selectbox("Class", CLASSES)
duration = st.number_input("Duration (hours)", min_value=0.0, step=0.5)
days_left = st.number_input("Days Left Before Departure", min_value=0, step=1)

# Predict button
if st.button("Predict Price"):
    duration_category = get_duration_category(duration)
    route = f"{source_city}-{destination_city}"

    input_data = pd.DataFrame([{
        "airline": airline_le.transform([airline])[0],
        "flight": flight_le.transform([flight])[0],
        "source_city": city_le.transform([source_city])[0],
        "departure_time": time_le.transform([departure_time])[0],
        "stops": stops_le.transform([stops])[0],
        "arrival_time": time_le.transform([arrival_time])[0],
        "destination_city": city_le.transform([destination_city])[0],
        "class": class_le.transform([travel_class])[0],
        "duration": duration,
        "days_left": days_left,
        "duration_category": duration_cat_le.transform([duration_category])[0],
        "route": route_le.transform([route])[0]
    }])

    prediction = model.predict(input_data)[0]

    st.success(f"Predicted Flight Price: ₹{prediction:,.2f}")

    st.info(f"""
Input Summary:
Airline: {airline}
Flight: {flight}
Source City: {source_city}
Departure Time: {departure_time}
Stops: {stops}
Arrival Time: {arrival_time}
Destination City: {destination_city}
Class: {travel_class}
Duration: {duration} hrs
Days Left: {days_left}
""")

    # ---------------------------------------------------------
    # Engineered / added columns (derived automatically at
    # predict time, not entered directly by the user):
    # duration_category and route.
    # ---------------------------------------------------------
    st.subheader("Engineered Features (added columns)")
    engineered_df = pd.DataFrame({
        "Feature": ["duration_category", "route"],
        "Value": [duration_category, route],
        "Encoded Value": [
            int(duration_cat_le.transform([duration_category])[0]),
            int(route_le.transform([route])[0]),
        ],
    })
    st.table(engineered_df)